"use strict";parserFactory.register("liberspark.com",()=>new LibersparkParser),parserFactory.register("veratales.com",()=>new LibersparkParser);class LibersparkParser extends Parser{constructor(){super()}getChapterUrls(e){return HttpClient.wrapFetch(e.baseURI).then(function(e){let r=e.responseXML.querySelector("table#novel-chapters-list");return util.hyperlinksToChapterList(r).reverse()})}findContent(e){return e.querySelector("div#chapter_body")}extractTitleImpl(e){return e.querySelector("h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.card-header")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.novel-synopsis")]}}